141	\begin{theorem}\leanok
142	[Pull-back of $\mathcal O$-modules preserves the unit]
143	  \label{thm:SheafOfModules_pullback_oneIso}
144	  \lean{AlgebraicGeometry.Scheme.SheafOfModules.pullback_oneIso}
145	  Let $f \colon X \to Y$ be a morphism of schemes. The categorical pull-back functor $f^* := \mathrm{Scheme.Modules.pullback}\,f$ preserves the tensor unit: there is a natural isomorphism
146	  \[
